        practice: [q("complete", "Today I'd ____ to propose a four-week trial.", "gostaria", "like"), q("complete", "The key ____ is access after nine.", "ponto", "point"), q("complete", "The results ____ to show higher demand on Fridays.", "parecem", "appear"), q("complete", "You may be ____ that the change will cost too much.", "preocupado", "concerned"), q("complete", "To sum ____, the trial would limit financial risk.", "resumindo", "up"), q("choose", "Choose the appropriately cautious prediction.", "outcome not tested yet", "The change may reduce missed connections.", ["The change will definitely end all missed connections.", "The change may reduce missed connections."]), q("error", "First of all, I will to explain the problem.", "will + base", "First of all, I will explain the problem."), q("reorder", "recommend / I / trial / a / starting / limited", "recommend + -ing", "I recommend starting a limited trial."), q("transform", "Some people think the plan is expensive.", "address as objection", "You may be concerned that the plan is expensive."), q("complete", "The survey ____ that twenty-three people need a later service.", "mostra", "shows")],
