        dialogues: [dialogue("Reducing a project scope", "Colleagues prepare a short proposal.", [["A", "We cannot solve every communication problem in one project."], ["B", "Then let's cut the scope down to missed booking reminders."], ["A", "Good. We have four weeks of cancellation data to back it up."], ["B", "I will map out the trial and the measurement."]]), dialogue("Checking an unclear slide", "A presenter asks for feedback.", [["Presenter", "Does this sentence get the main point across?"], ["Reviewer", "Not yet. What does 'this problem' refer to?"], ["Presenter", "The repeated delivery delay."], ["Reviewer", "Name it directly, then tie it to the proposed tracking system."], ["Presenter", "That is clearer. I will revise the slide."], ["Reviewer", "Great. We can run through it again afterwards."]]), dialogue("Preparing for questions", "A friend tests an objection.", [["Friend", "What if someone says the trial is too expensive?"], ["Speaker", "I will explain the spending limit and compare it with the current cost."]]), dialogue("Ending on time", "A teammate watches a rehearsal.", [["Teammate", "You have thirty seconds left."], ["Speaker", "Then I will cut the second example."], ["Teammate", "Good. Wrap up with the recommendation and the three measures."], ["Speaker", "That will keep the ending concise."]])],
        reading: { title: "How Feedback Changed the Proposal", genre: "Project development log", paragraphs: ["A student's first proposal aimed to 'make the whole town greener'. It included recycling, buses, gardens and energy use. The ideas were positive, but the scope was too broad for a five-minute presentation, and the evidence did not support one clear action.", "After feedback, the student focused on food packaging at one weekend market. She counted the number of disposable containers used by five stalls and interviewed vendors about storage and washing. These details supported a four-week reusable-container trial.", "The revised proposal acknowledged two objections: initial cost and responsibility for cleaning. It suggested a spending limit and one paid cleaning hour after each market. The outcome would be measured through returned containers, replacement cost and vendor feedback.", "The final version was not more persuasive because it used more advanced grammar. It improved because every section supported the same practical claim and prepared the audience for a decision."], vocabulary: [["vendor", "vendedor / feirante"], ["acknowledge", "reconhecer"], ["initial", "inicial"], ["claim", "afirmação central"]], questions: [rq("Why was the first proposal unsuitable for a short presentation?", "Its scope covered too many unrelated areas."), rq("Which evidence did the student collect after narrowing the topic?", "Container counts and vendor interviews."), rq("Which two objections did the revised proposal answer?", "Initial cost and cleaning responsibility."), rq("Why did the final version become more persuasive?", "Every section supported one practical claim and prepared a decision.")] },
        listening: { title: "Teacher Listening: Rehearsal Feedback", setup: "O professor lê o feedback duas vezes. O aluno cria uma lista de três revisões prioritárias.", script: "Your opening clearly identifies the unused-booking problem, and the number from the monthly report is strong evidence. However, the second example is about a different building and makes the scope less clear. Cut that example, explain who will send the automatic reminder and wrap up by naming the two results you will measure. The language is already accurate enough; focus the next rehearsal on timing and questions.", questions: [rq("Which two parts are already strong?", "The opening and the evidence from the monthly report."), rq("Why should the second example be removed?", "It concerns a different building and weakens the scope."), rq("Which responsibility needs to be explained?", "Who will send the automatic reminder."), rq("What should the next rehearsal focus on?", "Timing and questions.")] },
        expressionTranslations: [tr("Planeje as cinco partes antes de escrever.", "Map out the five sections before writing."), tr("Reduza a introdução para três frases.", "Cut the introduction down to three sentences."), tr("A conclusão deve ligar evidência e ação.", "The conclusion should tie the evidence and action together."), tr("Sustente cada afirmação com evidência.", "Back up each claim with evidence."), tr("Vamos ensaiar as perguntas mais uma vez.", "Let's run through the questions once more."), tr("Encerre com uma recomendação clara.", "Wrap up with a clear recommendation.")],
        speaking: { title: "Final Project Rehearsal", scenario: "O aluno apresenta a versão preliminar do projeto e a revisa após feedback de conteúdo, clareza e tempo.", languageBank: ["The main issue is...", "According to...", "For this reason...", "You may be concerned that...", "The result can be measured by..."], rounds: ["Apresente a primeira versão em até quatro minutos.", "Responda a quatro perguntas sem ler o roteiro.", "Refaça abertura e conclusão após feedback."], teacherFocus: "Priorize coerência, referência, evidência e resposta espontânea; registre apenas dois focos linguísticos para revisão final." },
        music: { song: "Unwritten", artist: "Natasha Bedingfield", focus: "Conecte rascunho, revisão e entrega. Complete o trecho original de prática.", lines: [["First I map the ", "outline", " and decide what matters most,"], ["then back each claim with evidence instead of a ", "boast", "."], ["I cut the extra detail and rehearse the final ", "part", ","], ["then wrap the message up with one clear place to ", "start", "."]], discussion: ["Which stage happens before drafting?", "What replaces unsupported claims?", "How does the speaker prepare the ending?"] },
